`,o.jsxs(n.p,{children:["Date: January 28, 2026",o.jsx(n.br,{}),`
`,"Authors: Protocol Genesis Team"]}),`
`,o.jsx(n.h3,{children:"Summary"}),`
`,o.jsx(n.p,{children:"Web3 vesting and lockups protect long-term alignment but trap billions in illiquid value. This protocol enables borrowing against the discounted present value (DPV) of time-locked tokens without transferring ownership or breaking vesting rules. Loans are issued non-custodially, settle automatically at unlock, and can optionally use identity signals to improve credit terms."}),`
`,o.jsx(n.h3,{children:"Problem"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Locked tokens have real market value but zero immediate utility."}),`
`,o.jsx(n.li,{children:"Existing DeFi lending requires liquid collateral."}),`
`,o.jsx(n.li,{children:"OTC sales and centralized loans are costly or custodial."}),`
`]}),`
`,o.jsx(n.h3,{children:"Solution"}),`
`,o.jsx(n.p,{children:"Borrow against vested or locked token claims, valued conservatively via DPV:"}),`
`,o.jsx(n.p,{children:"PV = Q * P * D"}),`
`,o.jsx(n.p,{children:"Where Q is token quantity, P is oracle price, and D is a composite discount factor (time, volatility, liquidity, unlock impact, protocol risk). LTV is capped and time-aware."}),`
`,o.jsx(n.h3,{children:"Key Features"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Non-custodial escrow of claim rights"}),`
`,o.jsx(n.li,{children:"On-chain enforcement at unlock"}),`
`,o.jsx(n.li,{children:"Conservative valuation curves (20-40% LTV caps)"}),`
`,o.jsx(n.li,{children:"Optional identity layer for better rates"}),`
`,o.jsx(n.li,{children:"Privacy-preserving participation: optional identity, selective disclosure, and private auctions to protect users who choose to exit early"}),`
`,o.jsx(n.li,{children:"Composable adapters for common vesting standards"}),`
`,o.jsx(n.li,{children:"Optional auction primitive for selling claim rights at market-clearing discounts"}),`
`]}),`
`,o.jsx(n.h3,{children:"Architecture"}),`
`,o.jsx(n.p,{children:"Core modules:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Vesting and lock adapters"}),`
`,o.jsx(n.li,{children:"Valuation and risk engine"}),`
`,o.jsx(n.li,{children:"Lending pools"}),`
`,o.jsx(n.li,{children:"Loan manager"}),`
`,o.jsx(n.li,{children:"Optional identity and reputation module"}),`
`,o.jsx(n.li,{children:"DAO governance and risk committees"}),`
`,o.jsx(n.li,{children:"Optional auction module (Dutch, English, Sealed Bid) for claim-right NFTs"}),`
`]}),`
`,o.jsx(n.h3,{children:"Loan Lifecycle"}),`
`,o.jsxs(n.ol,{children:[`
`,o.jsx(n.li,{children:"Escrow claim rights."}),`
`,o.jsx(n.li,{children:"Borrow stablecoins against DPV."}),`
`,o.jsx(n.li,{children:"Repay anytime with interest."}),`
`,o.jsx(n.li,{children:"At unlock: release on full repay, partial seize on underpayment, full liquidation on default."}),`
