`,o.jsx(n.h3,{children:"Optional Auction Path (Non-Loan Exit)"}),`
`,o.jsx(n.p,{children:"Users who prefer a debt-free exit can sell their claim rights via a time-bound auction:"}),`
`,o.jsxs(n.ol,{children:[`
`,o.jsx(n.li,{children:"Escrow claim rights as an NFT."}),`
`,o.jsx(n.li,{children:"Run a Dutch, English, or Sealed Bid auction for 1-7 days."}),`
