`,o.jsx(n.h3,{children:"Privacy and Safety for Early Exits"}),`
`,o.jsx(n.p,{children:"Some communities penalize members who exit vesting early. The protocol supports opt-in privacy that protects participants while keeping claims and settlement verifiable."}),`
`,o.jsx(n.p,{children:"Privacy model summary:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Goal: conceal borrower or seller identity and intent; preserve enforceability at unlock."}),`
`,o.jsx(n.li,{children:"Scope: protect against social pressure, targeted harassment, and coordination around early exits."}),`
`,o.jsx(n.li,{children:"Non-goal: hide the existence of the claim itself or bypass pool-level compliance."}),`
`]}),`
`,o.jsx(n.p,{children:"Mechanisms:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Optional identity: users can reveal identity signals for better terms or remain pseudonymous."}),`
`,o.jsx(n.li,{children:"Selective disclosure: proofs attest to eligibility (vesting schedule, unlock time, claim validity) without exposing the participant."}),`
`,o.jsx(n.li,{children:"Relayed actions: escrow, borrow, and settlement can be routed through relayers to reduce linkability."}),`
`,o.jsx(n.li,{children:"Private auctions: sealed-bid with commit/reveal limits signaling, collusion, and social pressure."}),`
`,o.jsx(n.li,{children:"Pool controls: DAOs can enable privacy modes per pool without weakening enforcement or lender protections."}),`
`]}),`
`,o.jsx(n.p,{children:"Assumptions and tradeoffs:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Privacy is opt-in; pools may price higher risk for fully private exits."}),`
`,o.jsx(n.li,{children:"Some pools require limited disclosures due to governance or compliance."}),`
`,o.jsx(n.li,{children:"Timing metadata may still leak behavioral signals."}),`
`]}),`
`,o.jsx(n.h3,{children:"Privacy Model (Appendix Summary)"}),`
`,o.jsx(n.p,{children:"This litepaper provides a high-level view. The full privacy model defines threat assumptions, adversaries, mitigations, and compliance modes."}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Goals: conceal participant identity and intent while keeping claims and settlement verifiable."}),`
`,o.jsx(n.li,{children:"Mechanisms: selective disclosure proofs, sealed-bid auctions, and relayer-based execution."}),`
`,o.jsx(n.li,{children:"Constraints: on-chain data remains public; privacy is opt-in and policy-driven per pool."}),`
`,o.jsxs(n.li,{children:["Details: see ",o.jsx(n.code,{children:"docs/PRIVACY_MODEL.md"})," and ",o.jsx(n.code,{children:"docs/TECHNICAL_SPEC.md"}),"."]}),`
`]}),`
