`,o.jsx(n.p,{children:"Current implementations:"}),`
`,o.jsxs(n.ul,{children:[`
`,o.jsx(n.li,{children:"Dutch (descending price): Fast resolution, low gas; risk of underselling if demand is thin."}),`
`,o.jsx(n.li,{children:"English (ascending bids): Maximizes seller revenue; slower and higher gas if many bids."}),`
`,o.jsx(n.li,{children:"Sealed Bid (first-price): Private bidding with commit/reveal; reduces collusion but adds complexity."}),`
