`,o.jsx(n.li,{children:"Transfer is disabled (soulbound), and the NFT can be burned on full repay."}),`
`,o.jsx(n.li,{children:"Provides immutable, on-chain evidence of terms for borrowers, lenders, and auditors."}),`
`]}),`
